                displayCardAnswerInternal()
            }
        }
    }

    private fun decodeEvaluateJavascriptResult(result: String?): String {
        if (result == null || result == "null" || result == "undefined") {
            return ""
        }
        return try {
            JSONArray("[$result]").optString(0, "")
        } catch (e: Exception) {
            Timber.w(e, "Failed to decode WebView JS result: %s", result)
            ""
